    private fun isAuthenticatedAndValid(): Boolean {
        val isAuthenticated = securePrefs.getBoolean(KEY_AUTHENTICATED, false)
        val authTimestamp = securePrefs.getLong(KEY_AUTH_TIMESTAMP, 0L)
        val currentTime = System.currentTimeMillis()

        if (isAuthenticated && (currentTime - authTimestamp) < AUTH_EXPIRY_MS) {
            return true
        }

        if (isAuthenticated && (currentTime - authTimestamp) >= AUTH_EXPIRY_MS) {
            clearAuthState()
        }

        return false
