    private fun setupBiometricAuthentication() {
        executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)

                    when (errorCode) {
                        BiometricPrompt.ERROR_NEGATIVE_BUTTON -> {
                            statusTextView.text = "Switched to password login"
                            showPasswordFallback()
                        }
                        BiometricPrompt.ERROR_LOCKOUT -> {
                            statusTextView.text =
                                "Too many attempts. Biometric locked. Use password."
                            biometricButton.isEnabled = false
                            showPasswordFallback()
                        }
                        BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                            statusTextView.text =
                                "Biometric permanently locked. Use password."
                            biometricButton.isEnabled = false
                            showPasswordFallback()
                        }
                        BiometricPrompt.ERROR_USER_CANCELED -> {
                            statusTextView.text = "Authentication cancelled"
                        }
                        BiometricPrompt.ERROR_CANCELED -> {
                            statusTextView.text = "Authentication cancelled"
                        }
                        else -> {
                            statusTextView.text = "Authentication error: $errString"
                            showPasswordFallback()
                        }
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)

                    val authenticationType = result.authenticationType
                    if (authenticationType == BiometricPrompt.AUTHENTICATION_RESULT_TYPE_BIOMETRIC) {
                        onAuthenticationSuccess("biometric")
                    } else {
                        statusTextView.text =
                            "Weak authentication detected. Please use strong biometric or password."
                        showPasswordFallback()
                    }
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    statusTextView.text = "Fingerprint not recognized. Try again."
                    Toast.makeText(
                        this@BiometricAuthActivity,
                        "Fingerprint not recognized",
                        Toast.LENGTH_SHORT
                    ).show()
