    private fun enableBiometricLogin() {
        if (!isBiometricAvailable()) {
            Toast.makeText(this, "Biometric hardware not available", Toast.LENGTH_LONG).show()
            return
        }

        val verifyPromptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Enable Biometric Login")
            .setSubtitle("Verify your fingerprint to enable biometric login")
            .setDescription("This will allow you to use your fingerprint for future logins")
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG)
            .setNegativeButtonText("Cancel")
            .setConfirmationRequired(true)
            .build()

        val enrollExecutor = ContextCompat.getMainExecutor(this)
        val enrollBiometricPrompt = BiometricPrompt(this, enrollExecutor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    if (result.authenticationType == BiometricPrompt.AUTHENTICATION_RESULT_TYPE_BIOMETRIC) {
                        securePrefs.edit().putBoolean(KEY_BIOMETRIC_ENABLED, true).apply()
                        setupBiometricButton.visibility = Button.GONE
                        statusTextView.text = "Biometric login enabled! You can now use fingerprint."
                        Toast.makeText(
