                }
            })

        enrollBiometricPrompt.authenticate(verifyPromptInfo)
    }

    private fun showPasswordFallback() {
        passwordLayout.visibility = LinearLayout.VISIBLE
        passwordEditText.requestFocus()
    }

    private fun handlePasswordLogin() {
        val password = passwordEditText.text.toString().trim()

        if (password.isEmpty()) {
            passwordEditText.error = "Password cannot be empty"
            return
        }

        if (validatePassword(password)) {
            onAuthenticationSuccess("password")
        } else {
            passwordEditText.error = "Invalid password"
            statusTextView.text = "Incorrect password. Please try again."
            Toast.makeText(this, "Invalid password", Toast.LENGTH_SHORT).show()
        }
    }

    private fun validatePassword(password: String): Boolean {
        // In production, validate against a securely stored hash (e.g., bcrypt)
        // This is a simplified example
        return password == HARDCODED_PASSWORD
    }

    private fun onAuthenticationSuccess(method: String) {
        securePrefs.edit()
            .putBoolean(KEY_AUTHENTICATED, true)
            .putLong(KEY_AUTH_TIMESTAMP, System.currentTimeMillis())
            .apply()

        statusTextView.text = "Authentication successful via $method!"
        Toast.makeText(this, "Welcome! Authenticated via $method", Toast.LENGTH_SHORT).show()

        navigateToMainScreen()
    }

    private fun navigateToMainScreen() {
        val intent = android.content.Intent(this, MainScreenActivity::class.java)
        intent.flags =
            android.content.Intent.FLAG_ACTIVITY_NEW_TASK or android.content.Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }

    private fun clearAuthState() {
        securePrefs.edit()
            .putBoolean(KEY_AUTHENTICATED, false)
            .putLong(KEY_AUTH_TIMESTAMP, 0L)
            .apply()
    }
}

